template<>
template<class Num>
consteval auto QuarticSplineKernel::unit_radius() noexcept -> Num {
  return Num{2.5};
}

// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

template<>
template<class Num>
constexpr auto QuarticSplineKernel::unit_value(Num q) noexcept -> Num {
  return (q < Num{2.5} ? pow((Num{2.5} + Num{-1.0} * q), 4) : Num{0.0}) +
         (q < Num{1.5} ? Num{-5.0} * pow((Num{1.5} + Num{-1.0} * q), 4) :
                         Num{0.0}) +
         (q < Num{0.5} ? Num{10.0} * pow((Num{0.5} + Num{-1.0} * q), 4) :
                         Num{0.0});
}

// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

template<>
template<class Num>
constexpr auto QuarticSplineKernel::unit_deriv(Num q) noexcept -> Num {
  return (q < Num{2.5} ? Num{-4.0} * pow((Num{2.5} + Num{-1.0} * q), 3) :
                         Num{0.0}) +
         (q < Num{1.5} ? Num{20.0} * pow((Num{1.5} + Num{-1.0} * q), 3) :
                         Num{0.0}) +
         (q < Num{0.5} ? Num{-40.0} * pow((Num{0.5} + Num{-1.0} * q), 3) :
                         Num{0.0});
}

// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

template<>
template<std::size_t Dim, class Num>
constexpr auto QuarticSplineKernel::unit_antideriv_moment(Num q) noexcept
    -> Num {
  if constexpr (Dim == 1) {
    return (q < Num{2.5} ?
                Num{-1.0 / 160.0} * pow((Num{-5.0} + Num{2.0} * q), 5) :
                Num{0.0}) +
           (q < Num{1.5} ?
                Num{1.0 / 32.0} * pow((Num{-3.0} + Num{2.0} * q), 5) :
                Num{0.0}) +
           (q < Num{0.5} ?
                Num{-1.0 / 16.0} * pow((Num{-1.0} + Num{2.0} * q), 5) :
                Num{0.0});
  } else if constexpr (Dim == 2) {
    return (q < Num{2.5} ?
                Num{-1.0 / 384.0} * pow((Num{-5.0} + Num{2.0} * q), 5) *
                    (Num{1.0} + Num{2.0} * q) :
                Num{0.0}) +
           (q < Num{1.5} ?
                Num{1.0 / 384.0} * pow((Num{-3.0} + Num{2.0} * q), 5) *
                    (Num{3.0} + Num{10.0} * q) :
                Num{0.0}) +
           (q < Num{0.5} ?
                Num{-1.0 / 192.0} * pow((Num{-1.0} + Num{2.0} * q), 5) *
                    (Num{1.0} + Num{10.0} * q) :
                Num{0.0});
  } else if constexpr (Dim == 3) {
    return (q < Num{2.5} ?
                Num{-1.0 / 2688.0} * pow((Num{-5.0} + Num{2.0} * q), 5) *
                    (Num{5.0} + Num{10.0} * q + Num{12.0} * pow(q, 2)) :
                Num{0.0}) +
           (q < Num{1.5} ?
                Num{1.0 / 896.0} * pow((Num{-3.0} + Num{2.0} * q), 5) *
                    (Num{3.0} + Num{10.0} * q + Num{20.0} * pow(q, 2)) :
                Num{0.0}) +
           (q < Num{0.5} ?
                Num{-1.0 / 1344.0} * pow((Num{-1.0} + Num{2.0} * q), 5) *
                    (Num{1.0} + Num{10.0} * q + Num{60.0} * pow(q, 2)) :
                Num{0.0});
  } else {
    static_assert(false);
  }
}

// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

template<>
template<class Num>
constexpr auto QuarticSplineKernel::unit_flux(Num eta,
                                              Num z_min,
                                              Num z_max) noexcept -> Num {
  return unit_segment_integral(Num{2.5},
                               eta,
                               z_min,
                               z_max,
                               impl::quartic_spline_gen::unit_flux_0<Num>) +
         unit_segment_integral(Num{1.5},
                               eta,
                               z_min,
                               z_max,
                               impl::quartic_spline_gen::unit_flux_1<Num>) +
         unit_segment_integral(Num{0.5},
                               eta,
                               z_min,
                               z_max,
                               impl::quartic_spline_gen::unit_flux_2<Num>);
}

// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

template<>
template<class Num>
constexpr auto QuarticSplineKernel::unit_flux(Num eta,
                                              const Vec<Num, 2>& a,
                                              const Vec<Num, 2>& b,
                                              const Vec<Num, 2>& c) noexcept
    -> Num {
  return unit_triangle_integral(
             Num{2.5},
             eta,
             a,
             b,
             c,
             impl::quartic_spline_gen::unit_flux_line_0<Num>,
             impl::quartic_spline_gen::unit_flux_sector_0<Num>) +
         unit_triangle_integral(
             Num{1.5},
             eta,
             a,
             b,
             c,
             impl::quartic_spline_gen::unit_flux_line_1<Num>,
             impl::quartic_spline_gen::unit_flux_sector_1<Num>) +
         unit_triangle_integral(
             Num{0.5},
             eta,
             a,
             b,
             c,
             impl::quartic_spline_gen::unit_flux_line_2<Num>,
             impl::quartic_spline_gen::unit_flux_sector_2<Num>);
}

