template<>
template<class Num>
consteval auto QuarticWendlandKernel::unit_radius() noexcept -> Num {
  return Num{2.0};
}

// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

template<>
template<class Num>
constexpr auto QuarticWendlandKernel::unit_value(Num q) noexcept -> Num {
  return (q < Num{2.0} ?
              pow((Num{1.0} + Num{-0.5} * q), 4) * (Num{1.0} + Num{2.0} * q) :
              Num{0.0});
}

// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

template<>
template<class Num>
constexpr auto QuarticWendlandKernel::unit_deriv(Num q) noexcept -> Num {
  return (q < Num{2.0} ? (Num{2.0} * pow((Num{1.0} + Num{-0.5} * q), 4) +
                          Num{-2.0} * pow((Num{1.0} + Num{-0.5} * q), 3) *
                              (Num{1.0} + Num{2.0} * q)) :
                         Num{0.0});
}

// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

template<>
template<std::size_t Dim, class Num>
constexpr auto QuarticWendlandKernel::unit_antideriv_moment(Num q) noexcept
    -> Num {
  if constexpr (Dim == 1) {
    return (q < Num{2.0} ?
                Num{-1.0 / 48.0} * pow((Num{-2.0} + q), 5) * (Num{1.0} + q) :
                Num{0.0});
  } else if constexpr (Dim == 2) {
    return (q < Num{2.0} ?
                Num{-1.0 / 224.0} * pow((Num{-2.0} + q), 5) *
                    (Num{2.0} + Num{4.0} * pow(q, 2) + Num{5.0} * q) :
                Num{0.0});
  } else if constexpr (Dim == 3) {
    return (q < Num{2.0} ? Num{-1.0 / 1344.0} * pow((Num{-2.0} + q), 5) *
                               (Num{8.0} + Num{20.0} * q +
                                Num{21.0} * pow(q, 3) + Num{30.0} * pow(q, 2)) :
                           Num{0.0});
  } else {
    static_assert(false);
  }
}

