// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

template<class Num>
constexpr auto unit_flux_0(Num eta,
                           Num z,
                           Num rho,
                           [[maybe_unused]] Num A,
                           Num L) noexcept -> Num {
  const auto t0 = pow(eta, 2);
  const auto t1 = pow(z, 2);
  const auto t2 = t0 * (Num{35.0 / 16.0} + Num{-93.0 / 256.0} * rho +
                        Num{35.0 / 768.0} * t0);
  const auto t3 =
      (Num{-7.0 / 3.0} + t0 * (Num{4.375} + t2 + Num{-77.0 / 24.0} * rho));
  const auto t4 = t0 * (Num{35.0 / 16.0} + Num{-163.0 / 384.0} * rho +
                        Num{35.0 / 576.0} * t0);
  const auto t5 =
      t0 * (Num{21.0 / 16.0} + Num{-25.0 / 96.0} * rho + Num{7.0 / 128.0} * t0);
  const auto t6 = (Num{5.0 / 16.0} + Num{-1.0 / 16.0} * rho +
                   Num{5.0 / 192.0} * t0 + Num{35.0 / 6912.0} * t1);
  const auto t7 = (Num{0.875} + t5 + Num{-7.0 / 9.0} * rho + t1 * t6);
  const auto t8 =
      (Num{-7.0 / 9.0} +
       t0 * (Num{35.0 / 12.0} + t4 + Num{-91.0 / 36.0} * rho) + t1 * t7);
  const auto t9 =
      L * pow(eta, 6) * (Num{-35.0 / 24.0} + Num{-35.0 / 256.0} * t0);
  return (t9 + z * (Num{1.0} + t0 * t3 + t1 * t8));
}

// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

template<class Num>
constexpr auto unit_antigrad_flux_0(Num eta,
                                    Num z,
                                    Num rho,
                                    Num A,
                                    Num L) noexcept -> Num {
  const auto t0 = pow(eta, 2);
  const auto t1 = pow(z, 2);
  const auto t2 = L * pow(eta, 7) * (Num{5.0 / 24.0} + Num{35.0 / 2304.0} * t0);
  const auto t3 = t0 * (Num{-35.0 / 128.0} + Num{-7.0 / 1536.0} * t0 +
                        Num{31.0 / 768.0} * rho);
  const auto t4 = (Num{7.0 / 12.0} +
                   t0 * (Num{-35.0 / 48.0} + t3 + Num{11.0 / 24.0} * rho));
  const auto t5 = t0 * (Num{-35.0 / 128.0} + Num{-7.0 / 1152.0} * t0 +
                        Num{163.0 / 3456.0} * rho);
  const auto t6 = t0 * (Num{-21.0 / 128.0} + Num{-7.0 / 1280.0} * t0 +
                        Num{25.0 / 864.0} * rho);
  const auto t7 = (Num{-5.0 / 128.0} + Num{-7.0 / 13824.0} * t1 +
                   Num{-1.0 / 384.0} * t0 + Num{1.0 / 144.0} * rho);
  const auto t8 = (Num{-7.0 / 48.0} + t6 + Num{1.0 / 9.0} * rho + t1 * t7);
  const auto t9 =
      (Num{7.0 / 36.0} +
       t0 * (Num{-35.0 / 72.0} + t5 + Num{13.0 / 36.0} * rho) + t1 * t8);
  return (t2 + A * Num{2.0 / 9.0} + eta * z * (Num{-0.5} + t0 * t4 + t1 * t9));
}

// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

template<class Num>
constexpr auto unit_flux_line_0(Num eta,
                                Num delta,
                                Num z,
                                Num rho,
                                Num A,
                                Num B,
                                Num L) noexcept -> Num {
  const auto t0 = pow(eta, 2);
  const auto t1 = pow(delta, 2);
  const auto t2 = Num{35.0 / 1536.0} * t0;
  const auto t3 = Num{35.0 / 768.0} * t0;
  const auto t4 = (Num{35.0 / 128.0} + t2);
  const auto t5 = pow(z, 2);
  const auto t6 = (A * Num{2.0 / 3.0} + B * Num{-2.0 / 3.0} +
                   t0 * (A * Num{1.0 / 18.0} + B * Num{-1.0 / 18.0}));
  const auto t7 = t1 * (Num{-5.0 / 24.0} + Num{-35.0 / 2304.0} * t1 +
                        Num{-5.0 / 64.0} * t0);
  const auto t8 = t1 * (t7 + t0 * (Num{-0.875} + Num{-21.0 / 128.0} * t0));
  const auto t9 =
      (t8 + pow(eta, 4) * (Num{-35.0 / 24.0} + Num{-35.0 / 192.0} * t0));
  const auto t10 =
      (t1 * t9 + pow(eta, 6) * (Num{-35.0 / 24.0} + Num{-35.0 / 256.0} * t0));
  const auto t11 = (Num{35.0 / 16.0} + Num{-29.0 / 24.0} * rho +
                    t0 * (Num{35.0 / 32.0} + t2 + Num{-325.0 / 2304.0} * rho));
  const auto t12 = (Num{35.0 / 16.0} + Num{-4.0 / 3.0} * rho +
                    t0 * (Num{105.0 / 64.0} + t3 + Num{-535.0 / 2304.0} * rho));
  const auto t13 =
      t1 * (t4 + Num{-31.0 / 768.0} * rho + Num{7.0 / 1536.0} * t1);
  const auto t14 = (Num{35.0 / 48.0} + t13 + Num{-11.0 / 24.0} * rho +
                    t0 * (Num{35.0 / 32.0} + t3 + Num{-367.0 / 2304.0} * rho));
  const auto t15 = t1 * (Num{-7.0 / 12.0} + t0 * t12 + t1 * t14);
  const auto t16 = t0 * (Num{35.0 / 64.0} + Num{35.0 / 2304.0} * t0 +
                         Num{-35.0 / 384.0} * rho);
  const auto t17 = t0 * (Num{35.0 / 48.0} + Num{-215.0 / 1728.0} * rho +
                         Num{35.0 / 1152.0} * t0);
  const auto t18 =
      t1 * (t4 + Num{-163.0 / 3456.0} * rho + Num{7.0 / 1152.0} * t1);
  const auto t19 =
      t1 * (Num{35.0 / 72.0} + t17 + t18 + Num{-13.0 / 36.0} * rho);
  const auto t20 =
      t0 * (Num{7.0 / 32.0} + Num{-11.0 / 288.0} * rho + Num{7.0 / 768.0} * t0);
  const auto t21 = (Num{21.0 / 128.0} + Num{-25.0 / 864.0} * rho +
                    Num{7.0 / 512.0} * t0 + Num{7.0 / 1280.0} * t1);
  const auto t22 =
      (Num{5.0 / 128.0} + Num{-1.0 / 144.0} * rho + Num{1.0 / 384.0} * t1 +
       Num{5.0 / 1536.0} * t0 + Num{7.0 / 13824.0} * t5);
  const auto t23 =
      (Num{7.0 / 48.0} + t20 + Num{-1.0 / 9.0} * rho + t1 * t21 + t22 * t5);
  const auto t24 =
      (Num{-7.0 / 36.0} + t19 +
       t0 * (Num{35.0 / 48.0} + t16 + Num{-19.0 / 36.0} * rho) + t23 * t5);
  const auto t25 =
      (Num{0.5} + t15 + t0 * (Num{-7.0 / 6.0} + t0 * t11) + t24 * t5);
  return (t6 * pow(eta, 7) + L * delta * t10 + delta * t25 * z);
}

// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

template<class Num>
constexpr auto unit_antigrad_flux_line_0(Num eta,
                                         Num delta,
                                         Num z,
                                         Num rho,
                                         Num A,
                                         Num B,
                                         Num L) noexcept -> Num {
  const auto t0 = pow(eta, 2);
  const auto t1 = pow(delta, 2);
  const auto t2 = delta * eta;
  const auto t3 = Num{-35.0 / 16896.0} * t0;
  const auto t4 = Num{-35.0 / 8448.0} * t0;
  const auto t5 = (Num{-35.0 / 1152.0} + t3);
  const auto t6 = pow(z, 2);
  const auto t7 = (A * Num{-1.0 / 12.0} + B * Num{1.0 / 12.0} +
                   t0 * (A * Num{-1.0 / 180.0} + B * Num{1.0 / 180.0}));
  const auto t8 =
      t1 * (Num{5.0 / 192.0} + Num{1.0 / 128.0} * t0 + Num{7.0 / 4608.0} * t1);
  const auto t9 = t1 * (t8 + t0 * (Num{7.0 / 64.0} + Num{21.0 / 1280.0} * t0));
  const auto t10 =
      (t9 + pow(eta, 4) * (Num{35.0 / 192.0} + Num{7.0 / 384.0} * t0));
  const auto t11 =
      (t1 * t10 + pow(eta, 6) * (Num{35.0 / 192.0} + Num{7.0 / 512.0} * t0));
  const auto t12 = (Num{-5.0 / 16.0} + Num{29.0 / 192.0} * rho +
                    t0 * (Num{-35.0 / 288.0} + t3 + Num{65.0 / 4608.0} * rho));
  const auto t13 = (Num{-5.0 / 16.0} + Num{1.0 / 6.0} * rho +
                    t0 * (Num{-35.0 / 192.0} + t4 + Num{107.0 / 4608.0} * rho));
  const auto t14 =
      t1 * (t5 + Num{-7.0 / 16896.0} * t1 + Num{31.0 / 7680.0} * rho);
  const auto t15 =
      (Num{-5.0 / 48.0} + t14 + Num{11.0 / 192.0} * rho +
       t0 * (Num{-35.0 / 288.0} + t4 + Num{367.0 / 23040.0} * rho));
  const auto t16 = t1 * (Num{7.0 / 60.0} + t0 * t13 + t1 * t15);
  const auto t17 = t0 * (Num{-35.0 / 576.0} + Num{7.0 / 768.0} * rho +
                         Num{-35.0 / 25344.0} * t0);
  const auto t18 = t0 * (Num{-35.0 / 432.0} + Num{-35.0 / 12672.0} * t0 +
                         Num{43.0 / 3456.0} * rho);
  const auto t19 =
      t1 * (t5 + Num{-7.0 / 12672.0} * t1 + Num{163.0 / 34560.0} * rho);
  const auto t20 =
      t1 * (Num{-5.0 / 72.0} + t18 + t19 + Num{13.0 / 288.0} * rho);
  const auto t21 = t0 * (Num{-7.0 / 288.0} + Num{-7.0 / 8448.0} * t0 +
                         Num{11.0 / 2880.0} * rho);
  const auto t22 = (Num{-7.0 / 384.0} + Num{-7.0 / 5632.0} * t0 +
                    Num{-7.0 / 14080.0} * t1 + Num{5.0 / 1728.0} * rho);
  const auto t23 = (Num{-5.0 / 1152.0} + Num{-7.0 / 152064.0} * t6 +
                    Num{-5.0 / 16896.0} * t0 + Num{-1.0 / 4224.0} * t1 +
                    Num{1.0 / 1440.0} * rho);
  const auto t24 =
      (Num{-1.0 / 48.0} + t21 + Num{1.0 / 72.0} * rho + t1 * t22 + t23 * t6);
  const auto t25 =
      (Num{7.0 / 180.0} + t20 +
       t0 * (Num{-5.0 / 48.0} + t17 + Num{19.0 / 288.0} * rho) + t24 * t6);
  const auto t26 =
      (Num{-1.0 / 6.0} + t16 + t0 * (Num{7.0 / 30.0} + t0 * t12) + t25 * t6);
  return (A * Num{64.0 / 495.0} + B * Num{-64.0 / 495.0} + t7 * pow(eta, 8) +
          L * t11 * t2 + t2 * t26 * z);
}

// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

template<class Num>
constexpr auto unit_flux_sector_0(Num eta) noexcept -> Num {
  const auto t0 = pow(eta, 2);
  const auto t1 = eta * (Num{-35.0 / 128.0} +
                         eta * (Num{1.0 / 18.0} + eta * Num{-7.0 / 1536.0}));
  const auto t2 = (Num{7.0 / 12.0} +
                   t0 * (Num{-35.0 / 48.0} + eta * (Num{2.0 / 3.0} + t1)));
  return (Num{2.0 / 9.0} + t0 * (Num{-0.5} + t0 * t2));
}

// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

template<class Num>
constexpr auto unit_antigrad_flux_sector_0(Num eta) noexcept -> Num {
  const auto t0 = pow(eta, 2);
  const auto t1 = eta * (Num{35.0 / 1152.0} +
                         eta * (Num{-1.0 / 180.0} + eta * Num{7.0 / 16896.0}));
  const auto t2 = (Num{-7.0 / 60.0} +
                   t0 * (Num{5.0 / 48.0} + eta * (Num{-1.0 / 12.0} + t1)));
  const auto t3 = eta * (Num{-2.0 / 9.0} + t0 * (Num{1.0 / 6.0} + t0 * t2));
  return (Num{64.0 / 495.0} + t3);
}

