template<>
template<class Num>
constexpr auto SixthOrderWendlandKernel::unit_flux(
    Num eta,
    const Vec<Num, 2>& a,
    const Vec<Num, 2>& b,
    const Vec<Num, 2>& c) noexcept -> Num {
  return unit_triangle_integral(
      Num{2.0},
      eta,
      a,
      b,
      c,
      impl::sixth_order_wendland_gen::unit_flux_line_0<Num>,
      impl::sixth_order_wendland_gen::unit_flux_sector_0<Num>);
}

