template<class Num>
constexpr auto unit_flux_0(Num eta,
                           Num z,
                           Num rho,
                           [[maybe_unused]] Num A,
                           Num L) noexcept -> Num {
  const auto t0 = pow(eta, 2);
  const auto t1 = pow(z, 2);
  const auto t2 = (Num{-1155.0 / 256.0} + Num{2123.0 / 2048.0} * rho +
                   t0 * (Num{-231.0 / 1024.0} + Num{793.0 / 65536.0} * rho));
  const auto t3 =
      t0 * (Num{-231.0 / 32.0} + Num{3069.0 / 512.0} * rho + t0 * t2);
  const auto t4 = (Num{-385.0 / 64.0} + Num{1639.0 / 1024.0} * rho +
                   t0 * (Num{-385.0 / 1024.0} + Num{2279.0 / 98304.0} * rho));
  const auto t5 =
      t0 * (Num{-231.0 / 32.0} + Num{1793.0 / 256.0} * rho + t0 * t4);
  const auto t6 = (Num{-693.0 / 128.0} + Num{1881.0 / 1280.0} * rho +
                   t0 * (Num{-231.0 / 512.0} + Num{3481.0 / 122880.0} * rho));
  const auto t7 =
      t0 * (Num{-693.0 / 160.0} + Num{275.0 / 64.0} * rho + t0 * t6);
  const auto t8 = (Num{-165.0 / 64.0} + Num{451.0 / 640.0} * rho +
                   t0 * (Num{-165.0 / 512.0} + Num{417.0 / 20480.0} * rho));
  const auto t9 = (Num{-385.0 / 768.0} + Num{11.0 / 80.0} * rho +
                   t0 * (Num{-385.0 / 3072.0} + Num{61.0 / 7680.0} * rho) +
                   t1 * (Num{-21.0 / 1024.0} + Num{1.0 / 768.0} * rho));
  const auto t10 =
      (Num{-33.0 / 32.0} + Num{33.0 / 32.0} * rho + t0 * t8 + t1 * t9);
  const auto t11 = (Num{-11.0 / 12.0} + t0 * (Num{2.75} + t5) +
                    t1 * (Num{0.825} + t7 + t1 * t10));
  const auto t12 =
      (Num{1.0} + t0 * (Num{-2.75} + t0 * (Num{4.125} + t3)) + t1 * t11);
  const auto t13 = L * pow(eta, 8) *
                   (Num{1155.0 / 512.0} +
                    t0 * (Num{693.0 / 2048.0} + Num{231.0 / 65536.0} * t0));
  return (t13 + t12 * z);
}

// ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

template<class Num>
constexpr auto unit_antigrad_flux_0(Num eta,
                                    Num z,
                                    Num rho,
                                    Num A,
                                    Num L) noexcept -> Num {
  const auto t0 = pow(eta, 2);
  const auto t1 = pow(z, 2);
  const auto t2 = L * pow(eta, 9) *
                  (Num{-385.0 / 1536.0} +
                   t0 * (Num{-63.0 / 2048.0} + Num{-231.0 / 851968.0} * t0));
  const auto t3 = (Num{231.0 / 512.0} + Num{-193.0 / 2048.0} * rho +
                   t0 * (Num{77.0 / 4096.0} + Num{-61.0 / 65536.0} * rho));
  const auto t4 =
      t0 * (Num{231.0 / 256.0} + Num{-341.0 / 512.0} * rho + t0 * t3);
  const auto t5 =
      (Num{77.0 / 128.0} + Num{-149.0 / 1024.0} * rho +
       t0 * (Num{385.0 / 12288.0} + Num{-2279.0 / 1277952.0} * rho));
  const auto t6 =
      t0 * (Num{231.0 / 256.0} + Num{-1793.0 / 2304.0} * rho + t0 * t5);
  const auto t7 = (Num{693.0 / 1280.0} + Num{-171.0 / 1280.0} * rho +
                   t0 * (Num{77.0 / 2048.0} + Num{-3481.0 / 1597440.0} * rho));
  const auto t8 =
      t0 * (Num{693.0 / 1280.0} + Num{-275.0 / 576.0} * rho + t0 * t7);
  const auto t9 = (Num{33.0 / 128.0} + Num{-41.0 / 640.0} * rho +
                   t0 * (Num{55.0 / 2048.0} + Num{-417.0 / 266240.0} * rho));
  const auto t10 = (Num{77.0 / 1536.0} + Num{-1.0 / 80.0} * rho +
                    t0 * (Num{385.0 / 36864.0} + Num{-61.0 / 99840.0} * rho) +
                    t1 * (Num{7.0 / 4096.0} + Num{-1.0 / 9984.0} * rho));
  const auto t11 =
      (Num{33.0 / 256.0} + Num{-11.0 / 96.0} * rho + t0 * t9 + t1 * t10);
  const auto t12 = (Num{11.0 / 48.0} + t0 * (Num{-11.0 / 24.0} + t6) +
                    t1 * (Num{-11.0 / 80.0} + t8 + t1 * t11));
  const auto t13 =
      (Num{-0.5} + t0 * (Num{11.0 / 16.0} + t0 * (Num{-11.0 / 16.0} + t4)) +
       t1 * t12);
  return (t2 + A * Num{7.0 / 39.0} + eta * t13 * z);
}

