template<class Num>
constexpr auto unit_flux_line_0(Num eta,
                                Num delta,
                                Num z,
                                Num rho,
                                Num A,
                                Num B,
                                Num L) noexcept -> Num {
  const auto t0 = pow(eta, 2);
  const auto t1 = pow(delta, 2);
  const auto t2 = pow(z, 2);
  const auto t3 = (A * Num{-0.125} + B * Num{0.125} +
                   t0 * (A * Num{-1.0 / 832.0} + B * Num{1.0 / 832.0}));
  const auto t4 = (A * Num{-11.0 / 12.0} + B * Num{11.0 / 12.0} + t0 * t3);
  const auto t5 = t0 * (Num{165.0 / 128.0} +
                        t0 * (Num{495.0 / 1024.0} + Num{165.0 / 16384.0} * t0));
  const auto t6 = t1 * (Num{63.0 / 2048.0} + Num{63.0 / 32768.0} * t0 +
                        Num{231.0 / 851968.0} * t1);
  const auto t7 = (Num{385.0 / 1536.0} + t6 +
                   t0 * (Num{385.0 / 2048.0} + Num{385.0 / 65536.0} * t0));
  const auto t8 =
      pow(eta, 4) * (Num{693.0 / 256.0} +
                     t0 * (Num{693.0 / 1024.0} + Num{693.0 / 65536.0} * t0));
  const auto t9 =
      pow(eta, 6) * (Num{385.0 / 128.0} +
                     t0 * (Num{1155.0 / 2048.0} + Num{231.0 / 32768.0} * t0));
  const auto t10 = t1 * (t9 + t1 * (t8 + t1 * (t5 + t1 * t7)));
  const auto t11 =
      pow(eta, 8) * (Num{1155.0 / 512.0} +
                     t0 * (Num{693.0 / 2048.0} + Num{231.0 / 65536.0} * t0));
  const auto t12 = (Num{-1155.0 / 512.0} + Num{843.0 / 2048.0} * rho +
                    t0 * (Num{-231.0 / 2048.0} + Num{4165.0 / 851968.0} * rho));
  const auto t13 =
      t0 * (Num{-231.0 / 64.0} + Num{3575.0 / 1536.0} * rho + t0 * t12);
  const auto t14 =
      (Num{-1155.0 / 256.0} + Num{921.0 / 1024.0} * rho +
       t0 * (Num{-1155.0 / 4096.0} + Num{11333.0 / 851968.0} * rho));
  const auto t15 =
      t0 * (Num{-693.0 / 128.0} + Num{5885.0 / 1536.0} * rho + t0 * t14);
  const auto t16 = (Num{-1155.0 / 256.0} + Num{473.0 / 512.0} * rho +
                    t0 * (Num{-385.0 / 1024.0} + Num{7749.0 / 425984.0} * rho));
  const auto t17 =
      t0 * (Num{-231.0 / 64.0} + Num{4037.0 / 1536.0} * rho + t0 * t16);
  const auto t18 =
      (Num{-1155.0 / 512.0} + Num{479.0 / 1024.0} * rho +
       t0 * (Num{-1155.0 / 4096.0} + Num{5881.0 / 425984.0} * rho));
  const auto t19 = (Num{-231.0 / 512.0} + Num{193.0 / 2048.0} * rho +
                    t0 * (Num{-231.0 / 2048.0} + Num{4737.0 / 851968.0} * rho) +
                    t1 * (Num{-77.0 / 4096.0} + Num{61.0 / 65536.0} * rho));
  const auto t20 =
      (Num{-231.0 / 256.0} + Num{341.0 / 512.0} * rho + t0 * t18 + t1 * t19);
  const auto t21 = (Num{-11.0 / 16.0} + t0 * (Num{33.0 / 16.0} + t15) +
                    t1 * (Num{11.0 / 16.0} + t17 + t1 * t20));
  const auto t22 =
      (Num{-385.0 / 256.0} + Num{359.0 / 1024.0} * rho +
       t0 * (Num{-385.0 / 4096.0} + Num{6587.0 / 1277952.0} * rho));
  const auto t23 =
      t0 * (Num{-231.0 / 128.0} + Num{385.0 / 256.0} * rho + t0 * t22);
  const auto t24 = (Num{-385.0 / 128.0} + Num{2201.0 / 3072.0} * rho +
                    t0 * (Num{-385.0 / 1536.0} + Num{35.0 / 2496.0} * rho));
  const auto t25 =
      t0 * (Num{-77.0 / 32.0} + Num{2365.0 / 1152.0} * rho + t0 * t24);
  const auto t26 =
      (Num{-1155.0 / 512.0} + Num{1667.0 / 3072.0} * rho +
       t0 * (Num{-1155.0 / 4096.0} + Num{10171.0 / 638976.0} * rho));
  const auto t27 =
      (Num{-77.0 / 128.0} + Num{149.0 / 1024.0} * rho +
       t0 * (Num{-77.0 / 512.0} + Num{1363.0 / 159744.0} * rho) +
       t1 * (Num{-385.0 / 12288.0} + Num{2279.0 / 1277952.0} * rho));
  const auto t28 =
      (Num{-231.0 / 256.0} + Num{1793.0 / 2304.0} * rho + t0 * t26 + t1 * t27);
  const auto t29 = (Num{-231.0 / 256.0} + Num{281.0 / 1280.0} * rho +
                    t0 * (Num{-77.0 / 1024.0} + Num{6853.0 / 1597440.0} * rho));
  const auto t30 =
      t0 * (Num{-231.0 / 320.0} + Num{121.0 / 192.0} * rho + t0 * t29);
  const auto t31 =
      (Num{-693.0 / 512.0} + Num{319.0 / 960.0} * rho +
       t0 * (Num{-693.0 / 4096.0} + Num{15547.0 / 1597440.0} * rho));
  const auto t32 = (Num{-693.0 / 1280.0} + Num{171.0 / 1280.0} * rho +
                    t0 * (Num{-693.0 / 5120.0} + Num{833.0 / 106496.0} * rho) +
                    t1 * (Num{-77.0 / 2048.0} + Num{3481.0 / 1597440.0} * rho));
  const auto t33 =
      (Num{-693.0 / 1280.0} + Num{275.0 / 576.0} * rho + t0 * t31 + t1 * t32);
  const auto t34 = (Num{-165.0 / 512.0} + Num{51.0 / 640.0} * rho +
                    t0 * (Num{-165.0 / 4096.0} + Num{621.0 / 266240.0} * rho));
  const auto t35 = (Num{-33.0 / 128.0} + Num{41.0 / 640.0} * rho +
                    t0 * (Num{-33.0 / 512.0} + Num{499.0 / 133120.0} * rho) +
                    t1 * (Num{-55.0 / 2048.0} + Num{417.0 / 266240.0} * rho));
  const auto t36 = (Num{-77.0 / 1536.0} + Num{1.0 / 80.0} * rho +
                    t0 * (Num{-77.0 / 6144.0} + Num{73.0 / 99840.0} * rho) +
                    t1 * (Num{-385.0 / 36864.0} + Num{61.0 / 99840.0} * rho) +
                    t2 * (Num{-7.0 / 4096.0} + Num{1.0 / 9984.0} * rho));
  const auto t37 = (Num{-33.0 / 256.0} + Num{11.0 / 96.0} * rho + t0 * t34 +
                    t1 * t35 + t2 * t36);
  const auto t38 = (Num{11.0 / 80.0} + t30 + t1 * t33 + t2 * t37);
  const auto t39 = (Num{-11.0 / 48.0} + t0 * (Num{11.0 / 16.0} + t23) +
                    t1 * (Num{11.0 / 24.0} + t25 + t1 * t28) + t2 * t38);
  const auto t40 =
      (Num{0.5} + t0 * (Num{-1.375} + t0 * (Num{33.0 / 16.0} + t13)) +
       t1 * t21 + t2 * t39);
  return (t4 * pow(eta, 9) + L * delta * (t10 + t11) + delta * t40 * z);
}

