template<>
template<class Num>
constexpr auto EighthOrderWendlandKernel::unit_flux(Num eta,
                                                    Num z_min,
                                                    Num z_max) noexcept -> Num {
  return unit_segment_integral(
      Num{2.0},
      eta,
      z_min,
      z_max,
      impl::eighth_order_wendland_gen::unit_flux_0<Num>);
}

